/// <summary>
/// Shared non-query SQL execution with <c>SqlStatementExecutePermission</c>.
/// </summary>
public final class SIMSStartSqlRunner
{
}

Method.Source:
/// <summary>
/// Executes a DDL/DML script and returns affected rows.
/// </summary>
/// <exception cref="Exception">Propagates database or permission failures.</exception>
public static int executeNonQuery(str _sql)
{
    int                 rowsAffected;
    Connection          connection = new Connection();
    Statement           statement = null;

    try
    {
        statement = connection.createStatement();

        var ssep = new SqlStatementExecutePermission(_sql);
        ssep.assert();
        rowsAffected = statement.executeUpdateWithParameters(_sql, null);
        CodeAccessPermission::revertAssert();
    }
    catch (Exception::CLRError)
    {
        System.Exception clrEx = CLRInterop::getLastException();

        if (clrEx != null)
        {
            throw error(clrEx.get_Message());
        }

        throw error("SQL execution failed.");
    }
    finally
    {
        if (statement != null)
        {
            statement.close();
        }
        connection.finalize();
    }

    return rowsAffected;
}
